409→DEFINE FUNCTION fn::entity_search_project($q: string, $limit: int, $workspace: record<workspace>, $project: record<project>) {
410→  LET $query = string::lowercase(string::trim($q));
411→  LET $safe_limit = math::min([math::max([$limit, 1]), 100]);
412→  LET $project_entity_ids = SELECT VALUE `in` FROM belongs_to WHERE out = $project;
413→
414→  LET $task_rows = SELECT
415→    id,
416→    "task" AS kind,
417→    title AS text,
418→    extraction_confidence AS confidence,
419→    source_message AS sourceMessage,
420→    priority,
421→    created_at
422→  FROM task
423→  WHERE workspace = $workspace
424→    AND extraction_confidence != NONE
425→    AND id IN $project_entity_ids
426→    AND string::contains(string::lowercase(title), $query)
427→  ORDER BY created_at DESC
428→  LIMIT $safe_limit;
429→
430→  LET $decision_rows = SELECT
431→    id,
432→    "decision" AS kind,
