150→export function parseRecordIdString<T extends string>(
151→  value: string,
152→  allowedTables: T[],
153→  fallbackTable?: T,
154→): RecordId<T, string> {
155→  const normalized = value.trim();
156→  if (normalized.length === 0) {
157→    throw new Error("record id is required");
158→  }
159→
160→  const separatorIndex = normalized.indexOf(":");
161→  if (separatorIndex === -1) {
162→    if (!fallbackTable) {
163→      throw new Error(`record id must be prefixed with one of: ${allowedTables.join(", ")}`);
164→    }
165→
166→    return new RecordId(fallbackTable, normalized) as RecordId<T, string>;
167→  }
168→
169→  const table = normalized.slice(0, separatorIndex) as T;
170→  const id = normalized.slice(separatorIndex + 1);
171→  if (!allowedTables.includes(table)) {
172→    throw new Error(`record id table must be one of: ${allowedTables.join(", ")}`);
173→  }
174→
175→  if (id.length === 0) {
176→    throw new Error("record id is missing its identifier component");
177→  }
178→
179→  return new RecordId(table, id) as RecordId<T, string>;
180→}
