 560→export async function resolveWorkspaceProjectRecord(input: {
 561→  surreal: Surreal;
 562→  workspaceRecord: RecordId<"workspace", string>;
 563→  projectInput: string;
 564→}): Promise<RecordId<"project", string>> {
 565→  const projectInput = input.projectInput.trim();
 566→  if (projectInput.length === 0) {
 567→    throw new Error("project identifier is required");
 568→  }
 569→
 570→  if (projectInput.includes(":")) {
 571→    const projectRecord = parseRecordIdString(projectInput, ["project"]);
 572→    const scoped = await isEntityInWorkspace(input.surreal, input.workspaceRecord, projectRecord);
 573→    if (!scoped) {
 574→      throw new Error("project is not linked to this workspace");
 575→    }
 576→    return projectRecord;
 577→  }
 578→
 579→  const projects = await getWorkspaceProjectRows(input.surreal, input.workspaceRecord);
 580→  const normalized = normalizeSearchValue(projectInput);
 581→
 582→  const exactMatch = projects.find((project) => normalizeSearchValue(project.name) === normalized);
 583→  if (exactMatch) {
 584→    return exactMatch.id;
 585→  }
 586→
 587→  const fuzzyMatches = projects.filter((project) => normalizeSearchValue(project.name).includes(normalized));
 588→  if (fuzzyMatches.length === 1) {
 589→    return fuzzyMatches[0].id;
 590→  }
 591→
 592→  if (fuzzyMatches.length > 1) {
 593→    throw new Error(`project input is ambiguous: ${fuzzyMatches.map((project) => project.name).join(", ")}`);
 594→  }
 595→
 596→  throw new Error(`project not found in workspace: ${projectInput}`);
 597→}
