 660→  const kinds = input.kinds && input.kinds.length > 0 ? input.kinds : SEARCH_KINDS;
 661→  const candidates: EntitySearchCandidate[] = [];
 662→  const projects = input.projectRecord ? [input.projectRecord] : (await getWorkspaceProjectRows(input.surreal, input.workspaceRecord)).map((row) => row.id);
 663→
 664→  if (kinds.includes("project")) {
 665→    const [rows] = await input.surreal
 666→      .query<[Array<{ id: RecordId<"project", string>; name: string; status: string; embedding?: number[] }>]>(
 667→        input.projectRecord
 668→          ? "SELECT id, name, status, embedding FROM project WHERE id = $project LIMIT 1;"
 669→          : "SELECT id, name, status, embedding FROM project WHERE id IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace) LIMIT $limit;",
 670→        input.projectRecord
 671→          ? { project: input.projectRecord }
 672→          : { workspace: input.workspaceRecord, limit: input.candidateLimit },
 673→      )
 674→      .collect<[Array<{ id: RecordId<"project", string>; name: string; status: string; embedding?: number[] }>]>();
 675→
 676→    for (const row of rows) {
 677→      candidates.push({
 678→        id: row.id,
 679→        kind: "project",
 680→        name: row.name,
 681→        status: row.status,
 682→        embedding: row.embedding,
 683→      });
 684→    }
 685→  }
 686→
 687→  if (kinds.includes("feature")) {
 688→    const [rows] = await input.surreal
 689→      .query<[Array<{ id: RecordId<"feature", string>; name: string; status: string; embedding?: number[] }>]>(
 690→        [
 691→          "SELECT id, name, status, embedding",
 692→          "FROM feature",
 693→          "WHERE id IN (",
 694→          "  SELECT VALUE out",
 695→          "  FROM has_feature",
 696→          input.projectRecord
 697→            ? "  WHERE `in` = $project"
 698→            : "  WHERE `in` IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
 699→          ")",
 700→          "LIMIT $limit;",
 701→        ].join(" "),
 702→        input.projectRecord
 703→          ? { project: input.projectRecord, limit: input.candidateLimit }
 704→          : { workspace: input.workspaceRecord, limit: input.candidateLimit },
 705→      )
 706→      .collect<[Array<{ id: RecordId<"feature", string>; name: string; status: string; embedding?: number[] }>]>();
 707→
 708→    for (const row of rows) {
