 833→export async function searchEntitiesByEmbedding(input: {
 834→  surreal: Surreal;
 835→  workspaceRecord: RecordId<"workspace", string>;
 836→  queryEmbedding: number[];
 837→  kinds?: SearchEntityKind[];
 838→  projectRecord?: RecordId<"project", string>;
 839→  limit: number;
 840→}): Promise<RankedEntity[]> {
 841→  const candidates = await listScopedEntityCandidates({
 842→    surreal: input.surreal,
 843→    workspaceRecord: input.workspaceRecord,
 844→    kinds: input.kinds,
 845→    projectRecord: input.projectRecord,
 846→    candidateLimit: Math.max(input.limit * 20, 120),
 847→  });
 848→
 849→  const rows = candidates
 850→    .map((candidate) => ({
 851→      candidate,
 852→      score: candidate.embedding ? cosineSimilarity(input.queryEmbedding, candidate.embedding) : -1,
 853→    }))
 854→    .filter((row) => row.score > 0)
 855→    .sort((a, b) => b.score - a.score)
 856→    .slice(0, input.limit);
 857→
 858→  return rows.map((row) => ({
 859→    id: toRecordIdString(row.candidate.id),
 860→    kind: row.candidate.kind,
 861→    name: row.candidate.name,
 862→    score: row.score,
 863→    ...(row.candidate.status ? { status: row.candidate.status } : {}),
 864→  }));
 865→}
