 867→export async function listEntityNeighbors(input: {
 868→  surreal: Surreal;
 869→  workspaceRecord: RecordId<"workspace", string>;
 870→  entityRecord: GraphEntityRecord;
 871→  limit: number;
 872→}): Promise<EntityNeighbor[]> {
 873→  const [rows] = await input.surreal
 874→    .query<[Array<{ in: GraphEntityRecord; out: GraphEntityRecord; kind: string; confidence: number; extracted_at: string | Date }>]>(
 875→      [
 876→        "SELECT `in`, out, kind, confidence, extracted_at",
 877→        "FROM entity_relation",
 878→        "WHERE `in` = $entity OR out = $entity",
 879→        "ORDER BY extracted_at DESC",
 880→        "LIMIT $limit;",
 881→      ].join(" "),
 882→      { entity: input.entityRecord, limit: input.limit },
 883→    )
 884→    .collect<[Array<{ in: GraphEntityRecord; out: GraphEntityRecord; kind: string; confidence: number; extracted_at: string | Date }>]>() ;
 885→
 886→  const neighbors: EntityNeighbor[] = [];
 887→
 888→  for (const row of rows) {
 889→    const direction = toRecordIdString(row.in) === toRecordIdString(input.entityRecord) ? "outgoing" : "incoming";
 890→    const neighborRecord = direction === "outgoing" ? row.out : row.in;
 891→
 892→    const scoped = await isEntityInWorkspace(input.surreal, input.workspaceRecord, neighborRecord);
 893→    if (!scoped) {
 894→      continue;
 895→    }
 896→
 897→    const name = await readEntityName(input.surreal, neighborRecord);
 898→    if (!name) {
 899→      continue;
 900→    }
 901→
 902→    neighbors.push({
 903→      id: toRecordIdString(neighborRecord),
 904→      kind: neighborRecord.table.name as GraphEntityTable,
 905→      name,
 906→      relationKind: row.kind,
 907→      direction,
 908→      confidence: row.confidence,
 909→    });
 910→  }
 911→
 912→  return neighbors;
 913→}
