 915→export async function getEntityDetail(input: {
 916→  surreal: Surreal;
 917→  workspaceRecord: RecordId<"workspace", string>;
 918→  entityRecord: GraphEntityRecord;
 919→}): Promise<EntityDetail> {
 920→  const scoped = await isEntityInWorkspace(input.surreal, input.workspaceRecord, input.entityRecord);
 921→  if (!scoped) {
 922→    throw new Error("entity is outside the current workspace scope");
 923→  }
 924→
 925→  const table = input.entityRecord.table.name as GraphEntityTable;
 926→  const row = await input.surreal.select<Record<string, unknown>>(input.entityRecord);
 927→  if (!row) {
 928→    throw new Error(`entity not found: ${table}:${toRecordIdString(input.entityRecord)}`);
 929→  }
 930→
 931→  const name = await readEntityName(input.surreal, input.entityRecord);
 932→  if (!name) {
 933→    throw new Error(`entity has no readable name field: ${table}:${toRecordIdString(input.entityRecord)}`);
 934→  }
 935→
 936→  const relationships = await listEntityNeighbors({
 937→    surreal: input.surreal,
 938→    workspaceRecord: input.workspaceRecord,
 939→    entityRecord: input.entityRecord,
 940→    limit: 40,
 941→  });
 942→
 943→  const [provenanceRows] = await input.surreal
 944→    .query<[
 945→      Array<{
 946→        in: RecordId<"message" | "document_chunk" | "git_commit", string>;
 947→        confidence: number;
 948→        extracted_at: string | Date;
 949→        evidence?: string;
 950→        evidence_source?: RecordId<"message", string>;
 951→        resolved_from?: RecordId<"message", string>;
 952→        from_text?: string;
 953→      }>,
 954→    ]>(
 955→      [
 956→        "SELECT `in`, confidence, extracted_at, evidence, evidence_source, resolved_from, from_text",
 957→        "FROM extraction_relation",
 958→        "WHERE out = $entity",
 959→        "AND (",
 960→        "  `in` IN (",
 961→        "    SELECT VALUE id",
 962→        "    FROM message",
 963→        "    WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)",
 964→        "  )",
 965→        "  OR `in` IN (SELECT VALUE id FROM document_chunk WHERE workspace = $workspace)",
 966→        "  OR `in` IN (SELECT VALUE id FROM git_commit WHERE workspace = $workspace)",
 967→        ")",
 968→        "ORDER BY extracted_at DESC",
 969→        "LIMIT 40;",
 970→      ].join(" "),
 971→      {
 972→        workspace: input.workspaceRecord,
 973→        entity: input.entityRecord,
 974→      },
 975→    )
 976→    .collect<[
 977→      Array<{
 978→        in: RecordId<"message" | "document_chunk" | "git_commit", string>;
 979→        confidence: number;
 980→        extracted_at: string | Date;
 981→        evidence?: string;
 982→        evidence_source?: RecordId<"message", string>;
 983→        resolved_from?: RecordId<"message", string>;
 984→        from_text?: string;
 985→      }>,
 986→    ]>();
 987→
 988→  // Resolve conversationIds for message-type provenance sources
 989→  const messageProvenanceRows = provenanceRows.filter((r) => r.in.table.name === "message");
 990→  let convMap: Map<string, string> | undefined;
 991→  if (messageProvenanceRows.length > 0) {
 992→    const [convRows] = await input.surreal
 993→      .query<[Array<{ id: RecordId<"message", string>; conversation: RecordId<"conversation", string> }>]>(
 994→        "SELECT id, conversation FROM message WHERE id IN $ids;",
 995→        { ids: messageProvenanceRows.map((r) => r.in) },
 996→      )
 997→      .collect<[Array<{ id: RecordId<"message", string>; conversation: RecordId<"conversation", string> }>]>();
 998→    convMap = new Map(convRows.map((r) => [r.id.id as string, r.conversation.id as string]));
 999→  }
1000→
1001→  const provenance = provenanceRows.map((row) => ({
1002→    sourceId: toRecordIdString(row.in),
1003→    sourceKind: row.in.table.name === "document_chunk"
1004→      ? "document_chunk"
1005→      : row.in.table.name === "git_commit"
1006→        ? "git_commit"
1007→        : "message",
1008→    confidence: row.confidence,
1009→    extractedAt: toIsoString(row.extracted_at),
1010→    ...(row.in.table.name === "message" && convMap?.get(row.in.id as string)
1011→      ? { conversationId: convMap.get(row.in.id as string) }
1012→      : {}),
1013→    ...(row.evidence ? { evidence: row.evidence } : {}),
1014→    ...(row.evidence_source ? { evidenceSource: toRecordIdString(row.evidence_source) } : {}),
1015→    ...(row.resolved_from ? { resolvedFrom: toRecordIdString(row.resolved_from) } : {}),
1016→    ...(row.from_text ? { fromText: row.from_text } : {}),
1017→  } satisfies EntityProvenance));
1018→
1019→  return {
1020→    entity: {
1021→      id: toRecordIdString(input.entityRecord),
1022→      kind: table,
1023→      name,
1024→      data: row,
1025→    },
1026→    relationships,
1027→    provenance,
1028→  };
1029→}
