1031→export async function getProjectStatus(input: {
1032→  surreal: Surreal;
1033→  workspaceRecord: RecordId<"workspace", string>;
1034→  projectInput: string;
1035→}): Promise<ProjectStatus> {
1036→  const projectRecord = await resolveWorkspaceProjectRecord({
1037→    surreal: input.surreal,
1038→    workspaceRecord: input.workspaceRecord,
1039→    projectInput: input.projectInput,
1040→  });
1041→
1042→  const project = await input.surreal.select<{ id: RecordId<"project", string>; name: string }>(projectRecord);
1043→  if (!project) {
1044→    throw new Error(`project not found: ${toRecordIdString(projectRecord)}`);
1045→  }
1046→
1047→  const [featureRows] = await input.surreal
1048→    .query<[Array<{ id: RecordId<"feature", string>; name: string; status: string }>]>(
1049→      "SELECT id, name, status FROM feature WHERE id IN (SELECT VALUE out FROM has_feature WHERE `in` = $project);",
1050→      { project: projectRecord },
1051→    )
1052→    .collect<[Array<{ id: RecordId<"feature", string>; name: string; status: string }>]>();
1053→
1054→  const [taskRows] = await input.surreal
1055→    .query<[Array<{ id: RecordId<"task", string>; title: string; status: string; priority?: string; created_at: string | Date }>]>(
1056→      [
1057→        "SELECT id, title, status, priority, created_at",
1058→        "FROM task",
1059→        "WHERE id IN (SELECT VALUE `in` FROM belongs_to WHERE out = $project)",
1060→        "OR id IN (",
1061→        "  SELECT VALUE out",
1062→        "  FROM has_task",
1063→        "  WHERE `in` IN (SELECT VALUE out FROM has_feature WHERE `in` = $project)",
1064→        ")",
1065→        "ORDER BY created_at DESC",
1066→        "LIMIT 100;",
1067→      ].join(" "),
1068→      { project: projectRecord },
1069→    )
1070→    .collect<[Array<{ id: RecordId<"task", string>; title: string; status: string; priority?: string; created_at: string | Date }>]>();
1071→
1072→  const [decisionRows] = await input.surreal
1073→    .query<[Array<{ id: RecordId<"decision", string>; summary: string; status: string; priority?: string; created_at: string | Date }>]>(
1074→      [
1075→        "SELECT id, summary, status, priority, created_at",
1076→        "FROM decision",
1077→        "WHERE id IN (SELECT VALUE `in` FROM belongs_to WHERE out = $project)",
1078→        "ORDER BY created_at DESC",
1079→        "LIMIT 30;",
1080→      ].join(" "),
1081→      { project: projectRecord },
1082→    )
1083→    .collect<[Array<{ id: RecordId<"decision", string>; summary: string; status: string; priority?: string; created_at: string | Date }>]>();
1084→
1085→  const [questionRows] = await input.surreal
1086→    .query<[Array<{ id: RecordId<"question", string>; text: string; status: string; priority?: string; created_at: string | Date }>]>(
1087→      [
1088→        "SELECT id, text, status, priority, created_at",
1089→        "FROM question",
1090→        "WHERE id IN (SELECT VALUE `in` FROM belongs_to WHERE out = $project)",
1091→        "ORDER BY created_at DESC",
1092→        "LIMIT 30;",
1093→      ].join(" "),
1094→      { project: projectRecord },
1095→    )
1096→    .collect<[Array<{ id: RecordId<"question", string>; text: string; status: string; priority?: string; created_at: string | Date }>]>();
1097→
1098→  let active = 0;
1099→  let completed = 0;
1100→  let blocked = 0;
1101→
1102→  for (const task of taskRows) {
1103→    const normalized = task.status.trim().toLowerCase();
1104→    if (normalized === "blocked") {
1105→      blocked += 1;
1106→      continue;
1107→    }
1108→
1109→    if (normalized === "done" || normalized === "completed") {
1110→      completed += 1;
1111→      continue;
1112→    }
1113→
1114→    active += 1;
1115→  }
1116→
1117→  return {
1118→    project: {
1119→      id: toRecordIdString(project.id),
1120→      name: project.name,
1121→    },
1122→    tasks: {
1123→      active,
1124→      completed,
1125→      blocked,
1126→      recent: taskRows.slice(0, 20).map((task) => ({
1127→        id: toRecordIdString(task.id),
1128→        name: task.title,
1129→        status: task.status,
1130→        ...(task.priority ? { priority: task.priority } : {}),
1131→      })),
1132→    },
1133→    decisions: decisionRows.map((decision) => ({
1134→      id: toRecordIdString(decision.id),
1135→      name: decision.summary,
1136→      status: decision.status,
1137→      ...(decision.priority ? { priority: decision.priority } : {}),
1138→    })),
1139→    questions: questionRows.map((question) => ({
1140→      id: toRecordIdString(question.id),
1141→      name: question.text,
1142→      status: question.status,
1143→      ...(question.priority ? { priority: question.priority } : {}),
1144→    })),
1145→    features: featureRows.map((feature) => ({
1146→      id: toRecordIdString(feature.id),
1147→      name: feature.name,
1148→      status: feature.status,
1149→    })),
1150→  };
1151→}
