1166→        { project: input.projectRecord },
1167→      )
1168→      .collect<[Array<RecordId<"task" | "decision" | "question", string>>]>();
1169→
1170→    const scopedEntities: Array<RecordId<string, string>> = [input.projectRecord, ...projectEntityRows];
1171→
