1188→          "ORDER BY createdAt DESC",
1189→          "LIMIT $limit;",
1190→        ].join(" "),
1191→        {
1192→          workspace: input.workspaceRecord,
1193→          entities: scopedEntities,
1194→          limit: Math.max(input.limit * 25, 250),
1195→        },
1196→      )
1197→      .collect<[
1198→        Array<{
1199→          id: RecordId<"message", string>;
1200→          conversation: RecordId<"conversation", string>;
1201→          text: string;
1202→          createdAt: string | Date;
1203→          embedding?: number[];
1204→        }>,
1205→      ]>();
1206→
1207→    rows = messageRows;
1208→  } else {
1209→    const [messageRows] = await input.surreal
1210→      .query<[
1211→        Array<{
1212→          id: RecordId<"message", string>;
1213→          conversation: RecordId<"conversation", string>;
1214→          text: string;
1215→          createdAt: string | Date;
1216→          embedding?: number[];
1217→        }>,
1218→      ]>(
1219→        [
1220→          "SELECT id, conversation, text, createdAt, embedding",
1221→          "FROM message",
1222→          "WHERE embedding != NONE",
1223→          "AND conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)",
1224→          "ORDER BY createdAt DESC",
1225→          "LIMIT $limit;",
1226→        ].join(" "),
1227→        {
1228→          workspace: input.workspaceRecord,
1229→          limit: Math.max(input.limit * 25, 250),
1230→        },
1231→      )
1232→      .collect<[
1233→        Array<{
1234→          id: RecordId<"message", string>;
1235→          conversation: RecordId<"conversation", string>;
1236→          text: string;
1237→          createdAt: string | Date;
1238→          embedding?: number[];
1239→        }>,
1240→      ]>();
1241→
1242→    rows = messageRows;
1243→  }
1244→
1245→  const ranked = rows
1246→    .map((row) => ({
1247→      row,
1248→      score: row.embedding ? cosineSimilarity(input.queryEmbedding, row.embedding) : -1,
1249→    }))
1250→    .filter((row) => row.score > 0)
1251→    .sort((a, b) => b.score - a.score)
1252→    .slice(0, input.limit)
1253→    .map((item) => ({
1254→      id: toRecordIdString(item.row.id),
1255→      conversationId: toRecordIdString(item.row.conversation),
1256→      text: item.row.text,
1257→      score: item.score,
1258→      createdAt: toIsoString(item.row.createdAt),
1259→    } satisfies RankedMessage));
1260→
1261→  return ranked;
1262→}
