1575→export async function getProjectGraphView(input: {
1576→  surreal: Surreal;
1577→  workspaceRecord: RecordId<"workspace", string>;
1578→  projectRecord: RecordId<"project", string>;
1579→}): Promise<GraphViewRawResult> {
1580→  const scoped = await isEntityInWorkspace(input.surreal, input.workspaceRecord, input.projectRecord);
1581→  if (!scoped) {
1582→    throw new Error("project is outside the current workspace scope");
1583→  }
1584→
1585→  const allRecords: GraphEntityRecord[] = [input.projectRecord as GraphEntityRecord];
1586→  const seen = new Set<string>();
1587→  seen.add(toRecordIdString(input.projectRecord));
1588→
1589→  const addRecord = (record: GraphEntityRecord) => {
1590→    const key = toRecordIdString(record);
1591→    if (!seen.has(key)) {
1592→      seen.add(key);
1593→      allRecords.push(record);
1594→    }
1595→  };
1596→
1597→  // Features via has_feature
1598→  const [featureRows] = await input.surreal
1599→    .query<[Array<RecordId<"feature", string>>]>(
1600→      "SELECT VALUE out FROM has_feature WHERE `in` = $project;",
1601→      { project: input.projectRecord },
1602→    )
1603→    .collect<[Array<RecordId<"feature", string>>]>();
1604→
1605→  for (const record of featureRows) {
1606→    addRecord(record as GraphEntityRecord);
1607→  }
1608→
1609→  // Tasks/decisions/questions via belongs_to WHERE out = project
1610→  const [belongsToRows] = await input.surreal
1611→    .query<[Array<RecordId<"task" | "decision" | "question", string>>]>(
1612→      "SELECT VALUE `in` FROM belongs_to WHERE out = $project;",
1613→      { project: input.projectRecord },
1614→    )
1615→    .collect<[Array<RecordId<"task" | "decision" | "question", string>>]>();
1616→
1617→  for (const record of belongsToRows) {
1618→    addRecord(record as GraphEntityRecord);
1619→  }
1620→
1621→  // Tasks via features' has_task + decisions/questions that belong_to features
1622→  if (featureRows.length > 0) {
1623→    const [featureTaskRows] = await input.surreal
1624→      .query<[Array<RecordId<"task", string>>]>(
1625→        "SELECT VALUE out FROM has_task WHERE `in` IN $features;",
1626→        { features: featureRows },
1627→      )
1628→      .collect<[Array<RecordId<"task", string>>]>();
1629→
1630→    for (const record of featureTaskRows) {
1631→      addRecord(record as GraphEntityRecord);
1632→    }
1633→
1634→    const [featureBelongsRows] = await input.surreal
1635→      .query<[Array<RecordId<"task" | "decision" | "question", string>>]>(
1636→        "SELECT VALUE `in` FROM belongs_to WHERE out IN $features;",
1637→        { features: featureRows },
1638→      )
1639→      .collect<[Array<RecordId<"task" | "decision" | "question", string>>]>();
1640→
1641→    for (const record of featureBelongsRows) {
1642→      addRecord(record as GraphEntityRecord);
1643→    }
1644→  }
1645→
1646→  // Entities extracted from workspace messages (catches decisions/questions/tasks without belongs_to edges)
1647→  const [provenanceRows] = await input.surreal
1648→    .query<[Array<GraphEntityRecord>]>(
1649→      [
1650→        "SELECT VALUE out FROM extraction_relation",
1651→        "WHERE `in` IN (SELECT VALUE id FROM message WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace));",
1652→      ].join(" "),
1653→      { workspace: input.workspaceRecord },
1654→    )
1655→    .collect<[Array<GraphEntityRecord>]>();
1656→
1657→  for (const record of provenanceRows) {
1658→    const table = record.table.name;
1659→    if (table === "task" || table === "decision" || table === "question" || table === "feature" || table === "person") {
1660→      addRecord(record as GraphEntityRecord);
1661→    }
1662→  }
1663→
1664→  // Persons via member_of WHERE out = workspace
1665→  const [personRows] = await input.surreal
1666→    .query<[Array<RecordId<"person", string>>]>(
1667→      "SELECT VALUE `in` FROM member_of WHERE out = $workspace;",
1668→      { workspace: input.workspaceRecord },
1669→    )
1670→    .collect<[Array<RecordId<"person", string>>]>();
1671→
1672→  for (const record of personRows) {
1673→    addRecord(record as GraphEntityRecord);
1674→  }
1675→
1676→  const entities = await resolveEntityNames(input.surreal, allRecords);
1677→  const edges = await collectEntityRelationEdges(input.surreal, allRecords);
1678→
1679→  return { entities, edges };
1680→}
