1682→export async function getFocusedGraphView(input: {
1683→  surreal: Surreal;
1684→  workspaceRecord: RecordId<"workspace", string>;
1685→  centerEntityRecord: GraphEntityRecord;
1686→  depth: number;
1687→}): Promise<GraphViewRawResult> {
1688→  const clampedDepth = Math.max(1, Math.min(3, input.depth));
1689→
1690→  const scoped = await isEntityInWorkspace(input.surreal, input.workspaceRecord, input.centerEntityRecord);
1691→  if (!scoped) {
1692→    throw new Error("entity is outside the current workspace scope");
1693→  }
1694→
1695→  const collected = new Map<string, GraphEntityRecord>();
1696→  collected.set(toRecordIdString(input.centerEntityRecord), input.centerEntityRecord);
1697→
1698→  let frontier: RecordId<string, string>[] = [input.centerEntityRecord];
1699→
1700→  for (let hop = 0; hop < clampedDepth; hop++) {
1701→    if (frontier.length === 0) {
1702→      break;
1703→    }
1704→
1705→    const [rows] = await input.surreal
1706→      .query<[EntityRelationRow[]]>(
1707→        [
1708→          "SELECT id, `in`, out, kind, confidence",
1709→          "FROM entity_relation",
1710→          "WHERE `in` IN $currentIds OR out IN $currentIds;",
1711→        ].join(" "),
1712→        { currentIds: frontier },
1713→      )
1714→      .collect<[EntityRelationRow[]]>();
1715→
1716→    const nextFrontier: RecordId<string, string>[] = [];
1717→
1718→    for (const row of rows) {
1719→      for (const endpoint of [row.in, row.out]) {
1720→        const key = toRecordIdString(endpoint);
1721→        if (collected.has(key)) {
1722→          continue;
1723→        }
1724→
1725→        const inScope = await isEntityInWorkspace(input.surreal, input.workspaceRecord, endpoint);
1726→        if (!inScope) {
1727→          continue;
1728→        }
1729→
1730→        collected.set(key, endpoint);
1731→        nextFrontier.push(endpoint);
1732→      }
1733→    }
1734→
1735→    frontier = nextFrontier;
1736→  }
1737→
1738→  const allRecords = Array.from(collected.values());
1739→  const entities = await resolveEntityNames(input.surreal, allRecords);
1740→  const edges = await collectEntityRelationEdges(input.surreal, allRecords);
1741→
1742→  return { entities, edges };
1743→}
